ALTER TABLE "FeatureSnapshot" ADD COLUMN "formulaVersion" TEXT NOT NULL DEFAULT '1.0.0', ADD COLUMN "sourceAvailableAt" TIMESTAMP(3), ADD COLUMN "provider" TEXT, ADD COLUMN "nullReason" TEXT, ADD COLUMN "warnings" JSONB;
ALTER TABLE "NormalizedFeatureSnapshot" ADD COLUMN "normalizationVersion" TEXT NOT NULL DEFAULT 'PERCENTILE_2_5_97_5_V1', ADD COLUMN "warnings" JSONB;
ALTER TABLE "FactorScoreSnapshot" ADD COLUMN "currentUniverseRank" INTEGER, ADD COLUMN "currentSectorRank" INTEGER, ADD COLUMN "currentIndustryRank" INTEGER, ADD COLUMN "alphaChange1d" DECIMAL(8,4), ADD COLUMN "alphaChange7d" DECIMAL(8,4), ADD COLUMN "alphaChange30d" DECIMAL(8,4), ADD COLUMN "rankChange1d" INTEGER, ADD COLUMN "rankChange30d" INTEGER;
ALTER TABLE "RiskMetricSnapshot" ADD COLUMN "maximumDrawdown3y" DECIMAL(18,10), ADD COLUMN "largestOneDayGap" DECIMAL(18,10), ADD COLUMN "recentGapFrequency" DECIMAL(18,10), ADD COLUMN "idiosyncraticVolatility" DECIMAL(18,10), ADD COLUMN "correlationSpy" DECIMAL(18,10), ADD COLUMN "missingBarPercent" DECIMAL(18,10);
ALTER TABLE "LiquiditySnapshot" ADD COLUMN "averageDollarVolume" DECIMAL(30,4), ADD COLUMN "medianShareVolume" DECIMAL(30,4);
CREATE TABLE "ModelCalculationRun" ("id" TEXT NOT NULL,"modelVersionId" TEXT NOT NULL,"asOfDate" TIMESTAMP(3) NOT NULL,"universeId" TEXT NOT NULL,"status" TEXT NOT NULL,"startedAt" TIMESTAMP(3) NOT NULL,"completedAt" TIMESTAMP(3),"securitiesEligible" INTEGER NOT NULL DEFAULT 0,"securitiesScored" INTEGER NOT NULL DEFAULT 0,"securitiesFailed" INTEGER NOT NULL DEFAULT 0,"errorSummary" TEXT,"metadata" JSONB,CONSTRAINT "ModelCalculationRun_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ModelCalculationFailure" ("id" TEXT NOT NULL,"runId" TEXT NOT NULL,"companyId" TEXT NOT NULL,"stage" TEXT NOT NULL,"message" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ModelCalculationFailure_pkey" PRIMARY KEY ("id"));
CREATE INDEX "ModelCalculationRun_asOfDate_status_idx" ON "ModelCalculationRun"("asOfDate","status"); CREATE INDEX "ModelCalculationRun_modelVersionId_asOfDate_idx" ON "ModelCalculationRun"("modelVersionId","asOfDate"); CREATE INDEX "ModelCalculationFailure_runId_idx" ON "ModelCalculationFailure"("runId");
ALTER TABLE "ModelCalculationRun" ADD CONSTRAINT "ModelCalculationRun_modelVersionId_fkey" FOREIGN KEY ("modelVersionId") REFERENCES "FactorModelVersion"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "ModelCalculationFailure" ADD CONSTRAINT "ModelCalculationFailure_runId_fkey" FOREIGN KEY ("runId") REFERENCES "ModelCalculationRun"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ModelCalculationFailure" ADD CONSTRAINT "ModelCalculationFailure_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE;
